targetCode.css:
body {
  margin: 0;
  min-height: 100vh;
  display: grid;
  place-items: center;
  background: #f6f1e7;
}

.escena {
  width: 420px;
  min-height: 240px;
  padding: 20px;
  border: 2px dashed #cbd5e1;
  overflow: auto;
}

#p1,
#p2 {
  display: block;
  width: 100px;
  height: 100px;
  border: 2px solid #0f172a;
  position: relative;
}

#p1 {
  background: #2563eb;
  float: left;
}

#p2 {
  background: #dc2626;
  float: left;
}

@media (min-width: 451px) {
  #p1,
  #p2 {
    float: right;
    clear: right;
  }

  #p1 {
    right: 0;
  }

  #p2 {
    right: 0;
    top: 6px;
  }
}
